export const icon = (key, size) => {
  const map = { keyboard: I.keyboard, trophy: I.trophy, bolt: I.bolt, crosshair: I.crosshair, chart: I.chart, star: I.star, cart: I.cart, crown: I.crown, gamepad: I.gamepad, trending: I.trending, signal: I.signal, gear: I.gear, refresh: I.refresh, lab: I.lab, user: I.user, globe: I.globe, fire: I.fire, viper: I.viper, skull: I.skull, skullr: (s) => I.skull(s, "#ef4444"), fang: I.fang, moon: I.moon, wave: I.wave, pulse: I.pulse, wing: I.wing, rdot: I.rdot, dragon: I.dragon, wolf: I.wolf, wind: I.wind, anchor: I.anchor, ninja: I.ninja, shield: I.shield };
  const fn = map[key];
  return fn ? fn(size || 20) : key;
};

